function descriptor(definition, element, slots = []) {
  return Object.freeze({
    schemaVersion: "2026-06-09.primitive-descriptor",
    component: definition.name,
    registryItem: definition.registryItem,
    namespace: definition.namespace,
    vocabularyHandshake: vocabularyHandshake.schemaVersion,
    sourceKind: "react-style-descriptor",
    implementationStatus: "framework-neutral-component-factory",
    implementationSource: "packages/ui/src/primitive-components.mjs",
    radixWrapper: false,
    runtimeReactRenderer: false,
    element,
    slots: Object.freeze(slots),
    propSchemaVersion: definition.propSchema.schemaVersion,
    propSchema: definition.propSchema,
    a11y: definition.aria,
    provenance: definition.provenance,
  });
}

const definitions = new Map(componentVocabulary.map((definition) => [definition.name, definition]));

export const primitiveDescriptors = Object.freeze({
  button: descriptor(definitions.get("button"), "button", ["children", "actionRef"]),
  panel: descriptor(definitions.get("panel"), "section", ["title", "children"]),
  "text-field": descriptor(definitions.get("text-field"), "input", ["label", "helperText", "errorText"]),
  "data-list": descriptor(definitions.get("data-list"), "table | ul", ["columns", "rows", "empty"]),
  "agent-panel": descriptor(definitions.get("agent-panel"), "section", ["status", "actionRefs", "artifactViewRefs"]),
  "docs-source-panel": descriptor(definitions.get("docs-source-panel"), "aside", ["sources", "selectedSourceId"]),
  "media-grid": descriptor(definitions.get("media-grid"), "ul", ["items", "selectedItemId"]),
});

export function getPrimitiveDescriptor(name) {
  return primitiveDescriptors[name] ?? null;
}

import {
  componentVocabulary,
  getComponentDefinition,
  validateComponentProps,
  vocabularyHandshake,
} from "./vocabulary.mjs";

export const PRIMITIVE_COMPONENT_IMPLEMENTATION_VERSION =
  "2026-06-09.framework-neutral-component-factory";

const byName = new Map(componentVocabulary.map((definition) => [definition.name, definition]));

function compactProps(props) {
  const out = {};
  for (const [key, value] of Object.entries(props)) {
    if (value !== undefined && value !== null && value !== false) out[key] = value;
  }
  return out;
}

function element(type, props = {}, ...children) {
  return {
    type,
    props: compactProps(props),
    children: children.flat().filter((child) => child !== undefined && child !== null && child !== false),
  };
}

function text(value) {
  return String(value ?? "");
}

function fallbackText(value, fallback) {
  const normalized = text(value).trim();
  return normalized.length > 0 ? normalized : fallback;
}

function slug(value) {
  const normalized = text(value)
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-|-$/g, "");
  return normalized || "field";
}

function safeArray(value) {
  return Array.isArray(value) ? value : [];
}

function displayValue(value) {
  if (value === null || value === undefined) return "";
  if (typeof value === "function" || typeof value === "symbol") return "[unsupported value]";
  if (typeof value === "object") {
    try {
      return JSON.stringify(value);
    } catch {
      return "[unserializable value]";
    }
  }
  return String(value);
}

function safeChild(value) {
  if (value === undefined || value === null || value === false) return null;
  return displayValue(value);
}

function collectSafeChildren(value, out, seen) {
  if (Array.isArray(value)) {
    if (seen.has(value)) {
      out.push("[unserializable value]");
      return out;
    }
    seen.add(value);
    for (const item of value) collectSafeChildren(item, out, seen);
    seen.delete(value);
    return out;
  }
  const child = safeChild(value);
  if (child !== null) out.push(child);
  return out;
}

function safeChildren(value) {
  return collectSafeChildren(value, [], new Set());
}

function childrenOrLabel(props, fallback) {
  if (props.children !== undefined) return safeChildren(props.children);
  if (props.label !== undefined) return [text(props.label)];
  return [fallback];
}

function normalizeVariant(value, fallback, allowed) {
  return allowed.includes(value) ? value : fallback;
}

function renderButton(props = {}) {
  const variant = normalizeVariant(props.variant, "primary", ["primary", "secondary", "ghost", "danger"]);
  const size = normalizeVariant(props.size, "regular", ["compact", "regular"]);
  const label = fallbackText(props.label ?? props.ariaLabel, props.loading ? "Loading" : "Action");
  return element(
    "button",
    {
      type: "button",
      className: "jami-button",
      "data-variant": variant,
      "data-size": size,
      "data-action-ref": props.actionRef,
      disabled: props.disabled || props.loading,
      "aria-busy": props.loading ? "true" : undefined,
      "aria-label": props.ariaLabel && !props.label ? props.ariaLabel : undefined,
    },
    ...childrenOrLabel({ ...props, label }, label),
  );
}

function renderPanel(props = {}) {
  const tone = normalizeVariant(props.tone, "neutral", ["neutral", "accent", "danger"]);
  const title = props.title ? element("h3", { className: "jami-panel-title" }, text(props.title)) : null;
  const body =
    props.empty === true
      ? element("p", { role: "status" }, "No content yet.")
      : props.error
        ? element("p", { role: "alert" }, text(props.error))
        : safeChildren(props.children);
  return element(
    "section",
    {
      className: "jami-panel",
      "data-tone": tone,
      "data-empty": props.empty ? "true" : undefined,
      role: "region",
      "aria-label": props.ariaLabel ?? props.title ?? "Panel",
    },
    title,
    ...body,
  );
}

function renderTextField(props = {}) {
  const id = `jami-field-${slug(props.label)}`;
  const helpId = props.helperText || props.errorText ? `${id}-help` : undefined;
  return element(
    "label",
    { className: "jami-field", htmlFor: id },
    element("span", { className: "jami-field-label" }, fallbackText(props.label, "Field")),
    element("input", {
      id,
      name: id,
      type: "text",
      defaultValue: props.value,
      placeholder: props.placeholder,
      disabled: props.disabled,
      "aria-invalid": props.invalid ? "true" : undefined,
      "aria-describedby": helpId,
    }),
    props.errorText
      ? element("span", { id: helpId, role: "alert" }, text(props.errorText))
      : props.helperText
        ? element("span", { id: helpId }, text(props.helperText))
        : null,
  );
}

function columnKey(column, index) {
  if (typeof column === "string") return column;
  return column?.key ?? `column-${index + 1}`;
}

function columnLabel(column, index) {
  if (typeof column === "string") return column;
  return column?.label ?? column?.key ?? `Column ${index + 1}`;
}

function renderDataList(props = {}) {
  const columns = safeArray(props.columns);
  const rows = safeArray(props.rows);
  const title = props.title ? element("h3", { className: "jami-data-list-title" }, text(props.title)) : null;
  const status =
    props.loading || props.empty || props.error || rows.length === 0
      ? element(
          "p",
          { role: props.error ? "alert" : "status" },
          props.error ? text(props.error) : props.loading ? "Loading records." : "No records to display.",
        )
      : null;
  const table =
    columns.length > 0 && rows.length > 0
      ? element(
          "table",
          { className: "jami-data-list-table" },
          element(
            "thead",
            {},
            element(
              "tr",
              {},
              ...columns.map((column, index) =>
                element("th", { scope: "col" }, text(columnLabel(column, index))),
              ),
            ),
          ),
          element(
            "tbody",
            {},
            ...rows.map((row) =>
              element(
                "tr",
                {},
                ...columns.map((column, index) =>
                  element("td", {}, displayValue(row?.[columnKey(column, index)])),
                ),
              ),
            ),
          ),
        )
      : null;
  return element(
    "section",
    {
      className: "jami-data-list",
      role: "region",
      "aria-label": props.ariaLabel ?? props.title ?? "Data list",
      "aria-busy": props.loading ? "true" : undefined,
    },
    title,
    status,
    table,
  );
}

function renderAgentPanel(props = {}) {
  const status = normalizeVariant(props.status, "idle", [
    "idle",
    "running",
    "needs_attention",
    "denied",
    "error",
  ]);
  const actionRefs = safeArray(props.actionRefs);
  const artifactViewRefs = safeArray(props.artifactViewRefs);
  return element(
    "section",
    {
      className: "jami-agent-panel",
      role: "status",
      "aria-live": "polite",
      "aria-label": props.title ?? props.agentName ?? "Agent status",
      "data-status": status,
    },
    element("h3", {}, fallbackText(props.title ?? props.agentName, "Agent")),
    element("p", {}, status.replaceAll("_", " ")),
    actionRefs.length
      ? element(
          "ul",
          { className: "jami-action-ref-list", "aria-label": "Action references" },
          ...actionRefs.map((ref) => element("li", { "data-action-ref": ref }, text(ref))),
        )
      : null,
    artifactViewRefs.length
      ? element(
          "ul",
          { className: "jami-artifact-ref-list", "aria-label": "Artifact view references" },
          ...artifactViewRefs.map((ref) => element("li", { "data-artifact-view-ref": ref }, text(ref))),
        )
      : null,
  );
}

function sourceId(source, index) {
  return source?.id ?? source?.sourceId ?? `source-${index + 1}`;
}

function sourceTitle(source, index) {
  return source?.title ?? source?.label ?? sourceId(source, index);
}

function renderDocsSourcePanel(props = {}) {
  const sources = safeArray(props.sources);
  const selectedSourceId = props.selectedSourceId ?? null;
  return element(
    "aside",
    {
      className: "jami-docs-source-panel",
      role: "complementary",
      "aria-label": props.ariaLabel ?? props.title ?? "Sources",
      "data-redacted": props.redacted ? "true" : undefined,
    },
    element("h3", {}, fallbackText(props.title, "Sources")),
    props.redacted ? element("p", { role: "status" }, "Source details are redacted.") : null,
    props.empty || sources.length === 0
      ? element("p", { role: "status" }, "No sources attached.")
      : element(
          "ul",
          { className: "jami-source-list" },
          ...sources.map((source, index) =>
            element(
              "li",
              {
                "data-source-id": sourceId(source, index),
                "aria-current": selectedSourceId === sourceId(source, index) ? "true" : undefined,
              },
              text(sourceTitle(source, index)),
            ),
          ),
        ),
  );
}

function mediaItemId(item, index) {
  return item?.id ?? item?.artifactId ?? `media-${index + 1}`;
}

function mediaItemLabel(item, index) {
  return item?.title ?? item?.label ?? item?.alt ?? mediaItemId(item, index);
}

function renderMediaGrid(props = {}) {
  const items = safeArray(props.items);
  const selectedItemId = props.selectedItemId ?? null;
  const status =
    props.error || props.loading || props.empty || items.length === 0
      ? element(
          "p",
          { role: props.error ? "alert" : "status" },
          props.error ? text(props.error) : props.loading ? "Loading media." : "No media items.",
        )
      : null;
  return element(
    "section",
    {
      className: "jami-media-grid",
      role: "region",
      "aria-label": props.ariaLabel ?? props.title ?? "Media",
      "aria-busy": props.loading ? "true" : undefined,
    },
    props.title ? element("h3", {}, text(props.title)) : null,
    status,
    items.length
      ? element(
          "ul",
          { className: "jami-media-grid-list" },
          ...items.map((item, index) =>
            element(
              "li",
              {
                "data-media-id": mediaItemId(item, index),
                "aria-current": selectedItemId === mediaItemId(item, index) ? "true" : undefined,
              },
              text(mediaItemLabel(item, index)),
            ),
          ),
        )
      : null,
  );
}

const renderers = Object.freeze({
  button: renderButton,
  panel: renderPanel,
  "text-field": renderTextField,
  "data-list": renderDataList,
  "agent-panel": renderAgentPanel,
  "docs-source-panel": renderDocsSourcePanel,
  "media-grid": renderMediaGrid,
});

export const primitiveComponentImplementations = Object.freeze(
  Object.fromEntries(
    componentVocabulary.map((definition) => [
      definition.name,
      Object.freeze({
        schemaVersion: PRIMITIVE_COMPONENT_IMPLEMENTATION_VERSION,
        component: definition.name,
        registryItem: definition.registryItem,
        namespace: definition.namespace,
        vocabularyHandshake: vocabularyHandshake.schemaVersion,
        propSchemaVersion: definition.propSchema.schemaVersion,
        implementationStatus: "framework-neutral-component-factory",
        source: "packages/ui/src/primitive-components.mjs",
        radixWrapper: false,
        runtimeReactRenderer: false,
        executableActions: false,
      }),
    ]),
  ),
);

export function getPrimitiveComponentImplementation(name) {
  return primitiveComponentImplementations[name] ?? null;
}

export function renderPrimitiveSpec(name, props = {}) {
  const definition = getComponentDefinition(name);
  if (!definition) {
    return {
      state: "unsupported",
      reasons: [`component ${name} is not part of the resident vocabulary`],
      node: element("section", { className: "jami-panel", role: "status" }, "Unsupported component."),
    };
  }
  const { children, ...schemaProps } = props;
  const reasons = validateComponentProps(name, schemaProps);
  if (reasons.length > 0) {
    return {
      state: "invalid",
      reasons,
      node: element("section", { className: "jami-panel", role: "alert", "data-tone": "danger" }, "Invalid props."),
    };
  }
  return {
    state: "renderable",
    reasons: [],
    node: renderers[name](props),
  };
}

export function createJamiPrimitiveComponents(createElement) {
  if (typeof createElement !== "function") {
    throw new TypeError("createJamiPrimitiveComponents requires a createElement function");
  }
  const fromSpec = (spec) => createElement(spec.type, spec.props, ...spec.children.map((child) => {
    if (child && typeof child === "object" && child.type && child.props && Array.isArray(child.children)) {
      return fromSpec(child);
    }
    return child;
  }));
  const make = (name) =>
    function JamiPrimitiveComponent(props = {}) {
      const result = renderPrimitiveSpec(name, props);
      return fromSpec(result.node);
    };
  return Object.freeze({
    Button: make("button"),
    Panel: make("panel"),
    TextField: make("text-field"),
    DataList: make("data-list"),
    AgentPanel: make("agent-panel"),
    DocsSourcePanel: make("docs-source-panel"),
    MediaGrid: make("media-grid"),
  });
}

export const primitiveComponentNames = Object.freeze([...byName.keys()]);

import * as React from "react";
import { Root as RadixLabelRoot } from "@radix-ui/react-label";
import { Slot } from "@radix-ui/react-slot";

export const JAMI_RADIX_REACT_WRAPPER_SOURCE = "packages/ui/src/radix-react-wrappers.mjs";

function h(type, props, ...children) {
  return React.createElement(type, props, ...children);
}

function joinClassNames(...values) {
  return values.filter(Boolean).join(" ");
}

function text(value) {
  return String(value ?? "");
}

function fallbackText(value, fallback) {
  const normalized = text(value).trim();
  return normalized.length > 0 ? normalized : fallback;
}

function safeArray(value) {
  return Array.isArray(value) ? value : [];
}

function displayValue(value) {
  if (value === null || value === undefined) return "";
  if (typeof value === "function" || typeof value === "symbol") return "[unsupported value]";
  if (typeof value === "object") {
    try {
      return JSON.stringify(value);
    } catch {
      return "[unserializable value]";
    }
  }
  return String(value);
}

function normalizeVariant(value, fallback, allowed) {
  return allowed.includes(value) ? value : fallback;
}

const URL_PROP_NAMES = new Set([
  "action",
  "background",
  "cite",
  "data",
  "formaction",
  "href",
  "manifest",
  "poster",
  "src",
  "srcset",
  "xlinkhref",
]);

function containsJavaScriptUrl(value) {
  if (typeof value !== "string") return false;
  return value
    .split(",")
    .some((part) =>
      part
        .replace(/[\u0000-\u001f\u007f\s]+/g, "")
        .toLowerCase()
        .startsWith("javascript:"),
    );
}

function isUnsafeProp(key, value) {
  const normalizedKey = key.replace(/[-_:]/g, "").toLowerCase();
  if (/^on[A-Za-z]/.test(key)) return true;
  if (
    normalizedKey === "dangerouslysetinnerhtml" ||
    normalizedKey === "innerhtml" ||
    normalizedKey === "outerhtml" ||
    normalizedKey === "srcdoc" ||
    normalizedKey === "html"
  ) {
    return true;
  }
  if (
    normalizedKey === "executable" ||
    normalizedKey === "canexecute" ||
    normalizedKey.includes("canexecute") ||
    normalizedKey.endsWith("executable")
  ) {
    return true;
  }
  if (URL_PROP_NAMES.has(normalizedKey)) {
    return containsJavaScriptUrl(value);
  }
  return false;
}

function slug(value) {
  const normalized = text(value)
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-|-$/g, "");
  return normalized || "field";
}

function compactProps(props) {
  const out = {};
  for (const [key, value] of Object.entries(props)) {
    if (isUnsafeProp(key, value)) continue;
    if (value !== undefined && value !== null && value !== false) out[key] = value;
  }
  return out;
}

function sanitizedCloneProps(props) {
  const out = {};
  for (const [key, value] of Object.entries(props)) {
    out[key] = isUnsafeProp(key, value) ? undefined : value;
  }
  return out;
}

function sanitizeReactNode(node) {
  if (Array.isArray(node)) return node.map((child) => sanitizeReactNode(child));
  if (!React.isValidElement(node)) return node;

  const { children, ...props } = node.props ?? {};
  return React.cloneElement(node, sanitizedCloneProps(props), sanitizeReactNode(children));
}

export const JamiButton = React.forwardRef(function JamiButton(
  {
    asChild = false,
    label,
    ariaLabel,
    variant = "primary",
    size = "regular",
    disabled = false,
    loading = false,
    actionRef,
    className,
    children,
    type = "button",
    ...domProps
  } = {},
  ref,
) {
  const Comp = asChild ? Slot : "button";
  const normalizedVariant = normalizeVariant(variant, "primary", [
    "primary",
    "secondary",
    "ghost",
    "danger",
  ]);
  const normalizedSize = normalizeVariant(size, "regular", ["compact", "regular"]);
  const content = sanitizeReactNode(children ?? fallbackText(label ?? ariaLabel, loading ? "Loading" : "Action"));
  return h(
    Comp,
    compactProps({
      ...domProps,
      ref,
      type: asChild ? undefined : type,
      className: joinClassNames("jami-button", className),
      "data-variant": normalizedVariant,
      "data-size": normalizedSize,
      "data-action-ref": actionRef,
      disabled: disabled || loading,
      "aria-disabled": asChild && (disabled || loading) ? "true" : undefined,
      "aria-busy": loading ? "true" : undefined,
      "aria-label": ariaLabel && !label && children === undefined ? ariaLabel : undefined,
    }),
    content,
  );
});

export const JamiPanel = React.forwardRef(function JamiPanel(
  {
    title,
    ariaLabel,
    tone = "neutral",
    empty = false,
    error,
    className,
    children,
    ...domProps
  } = {},
  ref,
) {
  const normalizedTone = normalizeVariant(tone, "neutral", ["neutral", "accent", "danger"]);
  const body = empty
    ? h("p", { role: "status" }, "No content yet.")
    : error
      ? h("p", { role: "alert" }, text(error))
      : sanitizeReactNode(children);
  return h(
    "section",
    compactProps({
      ...domProps,
      ref,
      className: joinClassNames("jami-panel", className),
      "data-tone": normalizedTone,
      "data-empty": empty ? "true" : undefined,
      role: "region",
      "aria-label": ariaLabel ?? title ?? "Panel",
    }),
    title ? h("h3", { className: "jami-panel-title" }, text(title)) : null,
    body,
  );
});

export const JamiTextField = React.forwardRef(function JamiTextField(
  {
    label,
    value,
    placeholder,
    disabled = false,
    invalid = false,
    errorText,
    helperText,
    id,
    className,
    inputClassName,
    ...inputProps
  } = {},
  ref,
) {
  const fieldLabel = fallbackText(label, "Field");
  const fieldId = id ?? `jami-field-${slug(fieldLabel)}`;
  const helpId = helperText || errorText ? `${fieldId}-help` : undefined;
  return h(
    RadixLabelRoot,
    {
      className: joinClassNames("jami-field", className),
      htmlFor: fieldId,
    },
    h("span", { className: "jami-field-label" }, fieldLabel),
    h(
      "input",
      compactProps({
        ...inputProps,
        ref,
        id: fieldId,
        name: inputProps.name ?? fieldId,
        className: inputClassName,
        type: inputProps.type ?? "text",
        defaultValue: value,
        placeholder,
        disabled,
        "aria-invalid": invalid ? "true" : undefined,
        "aria-describedby": helpId,
      }),
    ),
    errorText
      ? h("span", { id: helpId, role: "alert" }, text(errorText))
      : helperText
        ? h("span", { id: helpId }, text(helperText))
        : null,
  );
});

function columnKey(column, index) {
  if (typeof column === "string") return column;
  return column?.key ?? `column-${index + 1}`;
}

function columnLabel(column, index) {
  if (typeof column === "string") return column;
  return column?.label ?? column?.key ?? `Column ${index + 1}`;
}

export const JamiDataList = React.forwardRef(function JamiDataList(
  {
    title,
    ariaLabel,
    columns = [],
    rows = [],
    empty = false,
    loading = false,
    error,
    className,
    ...domProps
  } = {},
  ref,
) {
  const safeColumns = safeArray(columns);
  const safeRows = safeArray(rows);
  const status =
    loading || empty || error || safeRows.length === 0
      ? h(
          "p",
          { role: error ? "alert" : "status" },
          error ? text(error) : loading ? "Loading records." : "No records to display.",
        )
      : null;
  const table =
    safeColumns.length > 0 && safeRows.length > 0
      ? h(
          "table",
          { className: "jami-data-list-table" },
          h(
            "thead",
            null,
            h(
              "tr",
              null,
              ...safeColumns.map((column, index) => h("th", { scope: "col" }, text(columnLabel(column, index)))),
            ),
          ),
          h(
            "tbody",
            null,
            ...safeRows.map((row, rowIndex) =>
              h(
                "tr",
                { key: `row-${rowIndex}` },
                ...safeColumns.map((column, index) =>
                  h("td", { key: columnKey(column, index) }, displayValue(row?.[columnKey(column, index)])),
                ),
              ),
            ),
          ),
        )
      : null;
  return h(
    "section",
    compactProps({
      ...domProps,
      ref,
      className: joinClassNames("jami-data-list", className),
      role: "region",
      "aria-label": ariaLabel ?? title ?? "Data list",
      "aria-busy": loading ? "true" : undefined,
    }),
    title ? h("h3", { className: "jami-data-list-title" }, text(title)) : null,
    status,
    table,
  );
});

export const JamiAgentPanel = React.forwardRef(function JamiAgentPanel(
  {
    title,
    agentName,
    status = "idle",
    actionRefs = [],
    artifactViewRefs = [],
    className,
    ...domProps
  } = {},
  ref,
) {
  const normalizedStatus = normalizeVariant(status, "idle", [
    "idle",
    "running",
    "needs_attention",
    "denied",
    "error",
  ]);
  return h(
    "section",
    compactProps({
      ...domProps,
      ref,
      className: joinClassNames("jami-agent-panel", className),
      role: "status",
      "aria-live": "polite",
      "aria-label": title ?? agentName ?? "Agent status",
