function valueType(value) {
  if (Array.isArray(value)) return "array";
  if (value === null) return "null";
  return typeof value;
}

function validateValue(propName, value, rule, issues) {
  const actual = valueType(value);
  if (value === null && rule.nullable) return;
  if (actual !== rule.type) {
    issues.push(`prop ${propName} must be ${rule.type}`);
    return;
  }
  if (rule.enum && !rule.enum.includes(value)) {
    issues.push(`prop ${propName} must be one of ${rule.enum.join(", ")}`);
  }
  if (rule.pattern && typeof value === "string" && !new RegExp(rule.pattern).test(value)) {
    issues.push(`prop ${propName} does not match ${rule.pattern}`);
  }
  if (rule.type === "array" && rule.items) {
    for (const [index, item] of value.entries()) {
      validateValue(`${propName}[${index}]`, item, rule.items, issues);
    }
  }
}

export function validateComponentProps(componentName, props) {
  const definition = getComponentDefinition(componentName);
  if (!definition) return [`component ${componentName} has no prop schema`];
  if (props === undefined) return [];
  if (!props || typeof props !== "object" || Array.isArray(props)) {
    return [`props for ${componentName} must be an object`];
  }
  const schema = definition.propSchema;
  const issues = [];
  const properties = schema.properties ?? {};
  for (const required of schema.required ?? []) {
    if (!Object.hasOwn(props, required)) issues.push(`missing required prop ${required}`);
  }
  if (schema.additionalProperties === false) {
    for (const key of Object.keys(props)) {
      if (!Object.hasOwn(properties, key)) issues.push(`unsupported prop ${key} for ${componentName}`);
    }
  }
  for (const [key, value] of Object.entries(props)) {
    const rule = properties[key];
    if (rule) validateValue(key, value, rule, issues);
  }
  return issues;
}

/* Authored Studio UI resident vocabulary styles. Token variables are generated by packages/tokens. */
.jami-ui {
  color: var(--jami-semantic-light-foreground);
  background: var(--jami-semantic-light-background);
  font: var(--jami-typography-body);
}

.jami-button {
  align-items: center;
  border: 1px solid color-mix(in srgb, var(--jami-semantic-light-foreground) 18%, transparent);
  border-radius: var(--jami-radius-control);
  display: inline-flex;
  gap: var(--jami-spacing-control);
  justify-content: center;
  min-height: calc(var(--jami-spacing-control) * 5);
  padding: var(--jami-spacing-control) calc(var(--jami-spacing-control) * 1.5);
  transition-duration: var(--jami-motion-fast);
  transition-property: background-color, border-color, box-shadow, color;
}

.jami-button[data-variant="primary"] {
  background: var(--jami-semantic-light-accent);
  color: var(--jami-semantic-dark-foreground);
}

.jami-button:focus-visible,
.jami-panel:focus-visible,
.jami-field input:focus-visible,
.jami-data-list:focus-visible,
.jami-agent-panel:focus-visible,
.jami-docs-source-panel:focus-visible,
.jami-media-grid:focus-visible {
  outline: 2px solid var(--jami-componentState-focusRing);
  outline-offset: 2px;
}

.jami-button[disabled],
.jami-field input[disabled],
[aria-disabled="true"] {
  cursor: not-allowed;
  opacity: 0.58;
}

.jami-panel,
.jami-data-list,
.jami-agent-panel,
.jami-docs-source-panel,
.jami-media-grid {
  background: var(--jami-semantic-light-background);
  border: 1px solid color-mix(in srgb, var(--jami-semantic-light-foreground) 14%, transparent);
  border-radius: var(--jami-radius-control);
  box-shadow: var(--jami-shadow-overlay);
  color: var(--jami-semantic-light-foreground);
  min-width: 0;
  overflow-wrap: anywhere;
  padding: calc(var(--jami-spacing-control) * 2);
}

.jami-field {
  display: grid;
  gap: var(--jami-spacing-control);
}

.jami-field input {
  background: var(--jami-semantic-light-background);
  border: 1px solid color-mix(in srgb, var(--jami-semantic-light-foreground) 18%, transparent);
  border-radius: var(--jami-radius-control);
  color: var(--jami-semantic-light-foreground);
  min-height: calc(var(--jami-spacing-control) * 5);
  padding: var(--jami-spacing-control);
}

.jami-field [aria-invalid="true"] {
  border-color: var(--jami-semantic-light-accent);
}

.jami-data-list {
  display: grid;
  gap: var(--jami-spacing-control);
}

.jami-media-grid {
  display: grid;
  gap: var(--jami-spacing-control);
  grid-template-columns: repeat(auto-fit, minmax(10rem, 1fr));
}

@media (prefers-reduced-motion: reduce) {
  .jami-button {
    transition-duration: 0ms;
  }
}

@media (prefers-color-scheme: dark) {
  .jami-ui {
    color: var(--jami-semantic-dark-foreground);
    background: var(--jami-semantic-dark-background);
  }

  .jami-panel,
  .jami-data-list,
  .jami-agent-panel,
  .jami-docs-source-panel,
  .jami-media-grid,
  .jami-field input {
    color: var(--jami-semantic-dark-foreground);
    background: var(--jami-semantic-dark-background);
  }
}

